ee:message.ee:set-payload:
%dw 2.0
output application/json
var resultBody = payload.result default {}
var isError = (payload.status default "") == "error"
---
{ jsonrpc: "2.0", id: vars.rpcId, result: { content: [{ "type": "text", text: write(resultBody, "application/json") }], isError: isError } }

%dw 2.0
output application/json
---
{
  tools: [
    {
      name: "check_inventory",
      description: "部品の在庫レベル(quantityOnHand / available / leadTimeHours)を照会する。",
      inputSchema: {
        "type": "object",
        properties: {
          partNumber:       { "type": "string" },
          requiredQuantity: { "type": "integer" }
        },
        required: ["partNumber"]
      }
    },
    {
      name: "reserve_inventory",
      description: "部品在庫を仮確保(RESERVED)する。reservationId を返す。",
      inputSchema: {
        "type": "object",
        properties: {
          partNumber: { "type": "string" },
          quantity:   { "type": "integer" },
          incidentId: { "type": "string" },
          ttlSeconds: { "type": "integer" }
        },
        required: ["partNumber", "quantity", "incidentId"]
      }
    },
    {
      name: "cancel_inventory_reservation",
      description: "仮確保(reservationId)をキャンセルする。",
      inputSchema: {
        "type": "object",
        properties: { reservationId: { "type": "string" } },
        required: ["reservationId"]
      }
    }
  ]
}

%dw 2.0
output application/json
