ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
if (vars.toolInput.requiredQuantity != null)
  { "partNumber": (vars.toolInput.partNumber default "") as String, "requiredQuantity": (vars.toolInput.requiredQuantity as String) }
else
  { "partNumber": (vars.toolInput.partNumber default "") as String }

ee:message.ee:set-payload:
%dw 2.0
output application/json
var status = attributes.statusCode default 0
---
if (status >= 200 and status < 300)
  { status: "success", tool: vars.toolName, result: { reservationId: (vars.toolInput.reservationId default "") as String, "status": "CANCELLED" } }
else
  { status: "error",   tool: vars.toolName, result: (payload default { code: "BACKEND_ERROR", message: "inventory-system returned HTTP " ++ (status as String) }) }
